let isReplaying = false;
let currentActionIndex = 0;

// Loop processing variables
let currentRowData = null;
let sheetsManager = null;
let pendingRows = [];
let currentRowIndex = 0;
let config = null;
let skippedActionIds = [];

// Listen for replay commands
chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
  if (request.action === 'startReplay') {
    clearReplayState().then(() => startReplay(sendResponse));
    return true;
  } else if (request.action === 'startReplayLoop') {
    clearReplayState().then(() => startReplayLoop(request.config, sendResponse));
    return true;
  } else if (request.action === 'stopReplay') {
    stopReplay(sendResponse);
    return true;
  } else if (request.action === 'getStatus') {
    sendResponse({
      isReplaying,
      currentAction: currentActionIndex,
      totalActions: ACTIONS.length,
      currentRow: currentRowIndex,
      totalRows: pendingRows.length
    });
  }
  return true;
});

// Check for saved state on load (Resume functionality)
restoreReplayState().then(savedState => {
  if (savedState && savedState.isReplaying) {
    console.log('🔄 Replay state found! Resuming execution...');

    // Restore generic variables
    isReplaying = true;
    currentActionIndex = savedState.currentActionIndex + 1; // Resume from NEXT action

    if (savedState.mode === 'loop') {
      config = savedState.config;
      pendingRows = savedState.pendingRows || [];
      currentRowIndex = savedState.currentRowIndex || 0;

      console.log(`   Resuming LOOP at Row ${currentRowIndex}, Action ${currentActionIndex}`);

      // We need a dummy response function since we don't have a sender
      const dummySendResponse = () => { };

      // Wait a bit for page load then resume
      setTimeout(() => {
        resumeReplayLoop(dummySendResponse);
      }, 2000);

    } else {
      console.log(`   Resuming SINGLE replay at Action ${currentActionIndex}`);
      const dummySendResponse = () => { };
      setTimeout(() => {
        startReplay(dummySendResponse, true); // true = isResuming
      }, 2000);
    }
  }
});

// Start replaying actions
async function startReplay(sendResponse, isResuming = false) {
  if (isReplaying && !isResuming) {
    sendResponse({ success: false, error: 'Already replaying' });
    return;
  }

  isReplaying = true;
  if (!isResuming) currentActionIndex = 0;

  console.log(isResuming ? '🔄 Resuming replay...' : '▶️ Starting replay of', ACTIONS.length, 'actions');
  if (sendResponse) sendResponse({ success: true });

  try {
    for (let i = currentActionIndex; i < ACTIONS.length && isReplaying; i++) {
      currentActionIndex = i;
      const action = ACTIONS[i];

      // Save state before action (critical for navigation survival)
      await saveReplayState('single');

      console.log(`Executing action ${i + 1}/${ACTIONS.length}:`, action.type);

      await executeAction(action);

      // Notify background of progress
      chrome.runtime.sendMessage({
        action: 'replayProgress',
        current: i + 1,
        total: ACTIONS.length
      }).catch(() => { });

      // Wait between actions
      await wait(500);
    }

    console.log('Replay completed successfully');
    isReplaying = false;
    await clearReplayState(); // Clean up

    chrome.runtime.sendMessage({
      action: 'replayComplete',
      success: true
    }).catch(() => { });

  } catch (error) {
    console.error('Replay error:', error);
    isReplaying = false;
    // Don't clear state on error immediately, user might want to debug
    // await clearReplayState(); 

    chrome.runtime.sendMessage({
      action: 'replayComplete',
      success: false,
      error: error.message
    }).catch(() => { });
  }
}

// Stop replaying
async function stopReplay(sendResponse) {
  isReplaying = false;
  await clearReplayState();
  console.log('Replay stopped');
  if (sendResponse) sendResponse({ success: true });
}

// ========== LOOP PROCESSING ==========

/**
 * Resume loop processing from saved state
 */
async function resumeReplayLoop(sendResponse) {
  if (!config || !pendingRows) {
    console.error("Cannot resume loop: missing config or rows");
    return;
  }
  startReplayLoop(config, sendResponse, true);
}


/**
 * Processa múltiplas linhas da planilha em loop
 * @param {object} receivedConfig - Configuração recebida do popup
 * @param {function} sendResponse - Callback para resposta
 * @param {boolean} isResuming - Se está resumindo de um estado salvo
 */
async function startReplayLoop(receivedConfig, sendResponse, isResuming = false) {
  if (isReplaying && !isResuming) {
    sendResponse({ success: false, error: 'Já está processando' });
    return;
  }

  isReplaying = true;
  config = receivedConfig;
  pendingRows = config.pendingRows || [];
  skippedActionIds = [];

  if (!isResuming) {
    currentRowIndex = 0;
    console.log(`🎬 Iniciando processamento em loop de ${pendingRows.length} vídeo(s)`);
  } else {
    console.log(`🎬 Resumindo processamento em loop ${currentRowIndex + 1}/${pendingRows.length}`);
  }

  // Enviar resposta imediata
  if (sendResponse) sendResponse({ success: true });

  // Inicializar sheets manager (precisa estar no contexto da página)
  if (typeof GoogleSheetsManager === 'undefined') {
    console.error('❌ GoogleSheetsManager não encontrado. sheets-integration.js não foi carregado.');
    notifyError('Erro: GoogleSheetsManager não disponível');
    isReplaying = false;
    return;
  }

  try {
    sheetsManager = new GoogleSheetsManager(config.sheetUrl, config.sheetTab);
    await sheetsManager.validateSheet();

    let successCount = 0;
    let errorCount = 0;
    const errors = [];

    // Loop por cada linha pendente
    // Start from currentRowIndex (global) which is set by resume logic or initialized to 0
    for (; currentRowIndex < pendingRows.length; currentRowIndex++) {
      if (!isReplaying) {
        console.log('⏹ Processamento interrompido pelo usuário');
        break;
      }

      currentRowData = pendingRows[currentRowIndex];

      console.log(`\n📹 [${currentRowIndex + 1}/${pendingRows.length}] Processando:`);
      console.log(`   Linha: ${currentRowData.rowNumber}`);
      console.log(`   Título: "${currentRowData.tituloVideo}"`);
      console.log(`   Arquivo: ${currentRowData.nomeArquivo}`);

      // Notificar progresso
      chrome.runtime.sendMessage({
        action: 'replayProgress',
        current: currentRowIndex + 1,
        total: pendingRows.length,
        videoTitle: currentRowData.tituloVideo,
        fileName: currentRowData.nomeArquivo,
        status: 'Processando...'
      }).catch(() => { });

      try {
        // Executar todas as ações para esta linha
        // check if we need to resume inside the action loop
        const startActionIndex = isResuming ? currentActionIndex : 0;
        isResuming = false; // Reset flag after first use

        await executeAllActionsForRow(startActionIndex);

        // ✅ Sucesso - Atualizar planilha
        console.log(`✅ Vídeo processado com sucesso!`);

        try {
          await sheetsManager.updateStatus(currentRowData.rowNumber, 'Concluído');
          console.log(`   ✓ Planilha atualizada (linha ${currentRowData.rowNumber})`);
        } catch (updateError) {
          console.warn(`   ⚠️ Vídeo postado mas erro ao atualizar planilha:`,
            typeof updateError === 'object' ? JSON.stringify(updateError, Object.getOwnPropertyNames(updateError)) : updateError
          );
          // Não falha o processo, apenas avisa
        }

        successCount++;

      } catch (error) {
        // ❌ Erro      // Se erro de reload, parar loop silenciosamente
        if (error.message === "RELOADING_PAGE") {
          console.log("   🔄 Recarregando página para próxima etapa...");
          isReplaying = false;
          break;
        }

        console.error(`❌ Erro ao processar vídeo da linha ${currentRowData.rowNumber}:`, error);

        errorCount++;
        errors.push({
          rowNumber: currentRowData.rowNumber,
          videoTitle: currentRowData.tituloVideo,
          error: error.message
        });

        // Notificar erro
        chrome.runtime.sendMessage({
          action: 'replayError',
          rowNumber: currentRowData.rowNumber,
          videoTitle: currentRowData.tituloVideo,
          error: error.message
        }).catch(() => { });

        // 🛑 CRITICAL: User requested to STOP on error.
        // "a Extensão só pode passar para processar a próxima linha ... depois de concluir todas as ações"
        console.log('   🛑 Erro crítico detectado. Interrompendo processamento em loop.');
        isReplaying = false; // Stop the flag

        // Notify user of stoppage
        notifyError(`Processamento interrompido na linha ${currentRowData.rowNumber} devido a erro: ${error.message}`);

        break; // Break the loop
      }

      // Aguardar entre vídeos (evitar detecção de bot)
      if (currentRowIndex < pendingRows.length - 1) {
        const delayMs = 5000 + Math.random() * 3000; // 5-8 segundos
        console.log(`   ⏳ Aguardando ${(delayMs / 1000).toFixed(1)}s antes do próximo...`);
        await wait(delayMs);
      }
    }

    // Finalizado
    isReplaying = false;
    currentRowData = null;
    await clearReplayState();

    const message = `Processamento concluído!\n\n✅ Sucesso: ${successCount}\n❌ Erros: ${errorCount}`;

    console.log(`\n🎉 ${message}`);

    if (errors.length > 0) {
      console.log('\n📋 Erros detalhados:');
      errors.forEach(err => {
        console.log(`   - Linha ${err.rowNumber} (${err.videoTitle}): ${err.error}`);
      });
    }

    chrome.runtime.sendMessage({
      action: 'replayComplete',
      success: errorCount === 0,
      message: message,
      stats: { successCount, errorCount, total: pendingRows.length }
    }).catch(() => { });

  } catch (error) {
    console.error('❌ Erro fatal no loop:', error);
    isReplaying = false;
    await clearReplayState();

    chrome.runtime.sendMessage({
      action: 'replayComplete',
      success: false,
      message: `Erro fatal: ${error.message}`
    }).catch(() => { });
  }
}

/**
 * Executa todas as ações para a linha atual (currentRowData)
 */
async function executeAllActionsForRow(startIndex = 0) {
  console.log(`   ▶️ Executando ${ACTIONS.length} ações (Starting from ${startIndex})...`);

  for (let i = startIndex; i < ACTIONS.length && isReplaying; i++) {
    currentActionIndex = i;
    const action = ACTIONS[i];

    if (skippedActionIds.includes(action.id)) {
      console.log(`      ⏭️ Pulando ação já executada: ${action.id}`);
      continue;
    }

    // Save state before every action in the loop
    await saveReplayState('loop');

    console.log(`      [${i + 1}/${ACTIONS.length}] ${action.type}...`);

    await executeAction(action);

    // Esperar entre ações
    await wait(500);
  }

  console.log(`   ✓ Todas as ações executadas`);
}

// Execute a single action
async function executeAction(action) {
  if (action.waitBefore) {
    console.log(`   ⏳ Waiting ${action.waitBefore}ms before action...`);
    await wait(action.waitBefore);
  }

  let element = null;

  if (action.selector) {
    console.log(`   🔍 Procurando elemento: ${action.selector.css || action.selector.xpath}`);
    element = await findElement(action.selector);

    if (!element) {
      console.error(`   ❌ Elemento NÃO encontrado: ${action.selector.css || action.selector.xpath}`);
      throw new Error(`Element not found: ${action.selector.css || action.selector.xpath}`);
    }

    console.log(`   ✅ Elemento encontrado: ${element.tagName} (Classe: ${element.className})`);

    // Scroll element into view
    element.scrollIntoView({ behavior: 'smooth', block: 'center' });
    await wait(300);

    // Highlight element
    highlightElement(element);
  }



  // Execute action based on type
  switch (action.type) {
    case 'click':
      if (action.id === '1768509576488-bqmrfufae') {
        // --- 📅 TRATAMENTO DINÂMICO DE DATA ---
        console.log('      📅 Iniciando seleção dinâmica de data...');
        element.click(); // Abre o calendário
        await wait(1000);

        const targetDateStr = formatDateForSpotify(currentRowData.dataPostagem);
        console.log(`      🎯 Data Alvo: "${targetDateStr}"`);

        // XPath para encontrar a célula da data (td com aria-label terminando com a data)
        // Usamos contains para garantir
        const dateXpath = `//td[contains(@aria-label, '${targetDateStr}')]`;

        let dateFound = false;

        // Tentar encontrar a data (pode estar em outro mês)
        // Tentaremos navegar até 12 meses à frente se necessário
        for (let m = 0; m < 12; m++) {
          // Increase timeout to 2000ms to allow for render delays after clicking next
          const dateCell = await findElement({ xpath: dateXpath }, 2000);

          if (dateCell) {
            console.log('      ✅ Data encontrada! Clicando...');
            dateCell.click();
            dateFound = true;
            break;
          }

          console.log(`      ⚠️ Data não encontrada no mês atual (${m + 1}/12). Tentando avançar mês...`);

          // Buscar botão de próximo mês
          // Estratégia em camadas: Aria-Labels -> Seletor Gravado -> Classes CSS
          const nextBtnAction = ACTIONS.find(a => a.id === '1768509578090-4meyuf235');
          let nextBtn = null;

          // 1. Tentar seletores genéricos robustos (Acessibilidade)
          const ariaSelectors = [
            'div[role="button"][aria-label*="Move forward"]', // English (Airbnb react-dates)
            'div[role="button"][aria-label*="avançar"]',      // PT-BR generic
            'div[role="button"][aria-label*="Próximo"]',      // PT-BR common
            'button[aria-label*="Next month"]',
            'button[aria-label*="Próximo mês"]'
          ];

          // Tenta encontrar via CSS agrupado
          try {
            nextBtn = await findElement({ css: ariaSelectors.join(', ') }, 1000);
          } catch (e) { console.warn('Erro na busca por aria-labels:', e); }

          // 2. Se falhar, tentar o seletor ORIGINAL gravado (pode ser específico demais, mas é um bom fallback)
          if (!nextBtn && nextBtnAction && nextBtnAction.selector) {
            // console.log('      ⚠️ Tentando seletor gravado para botão "Próximo"...');
            nextBtn = await findElement(nextBtnAction.selector, 1000);
          }

          // 3. Fallback visual (ícone da seta)
          if (!nextBtn) {
            // console.warn('      ⚠️ Tentando fallback visual para botão "Próximo"...');
            const arrowSelector = {
              css: '.calendarDatePicker__navIcon--right, .DayPickerNavigation_button:last-child'
            };
            const arrowEl = await findElement(arrowSelector, 1000);

            if (arrowEl) {
              // O clique geralmente é no botão pai, não no ícone/svg
              nextBtn = arrowEl.closest('[role="button"]') || arrowEl.closest('button');

              // Se não achar pai clicável, tenta clicar no próprio elemento se ele parecer interativo
              if (!nextBtn && (arrowEl.tagName === 'BUTTON' || arrowEl.getAttribute('role') === 'button')) {
                nextBtn = arrowEl;
              }

              // Último recurso: clicar no ícone mesmo e esperar bubbling
              if (!nextBtn) nextBtn = arrowEl;
            }
          }

          if (nextBtn) {
            nextBtn.click();
            await wait(1000); // Esperar animação do calendário
          } else {
            console.error('      ❌ FALHA FATAL: Botão de próximo mês não encontrado após todas as tentativas.');
            // Dump do HTML da área do calendário para debug (se possível)
            throw new Error(`Botão 'Próximo Mês' não encontrado. Impossível navegar para a data: ${targetDateStr}`);
          }
        }

        if (!dateFound) {
          throw new Error(`Não foi possível encontrar a data: ${targetDateStr} no calendário.`);
        }

        // Marcar as ações manuais seguintes (nav e click data) para serem puladas
        skippedActionIds.push('1768509578090-4meyuf235'); // Botão Next Month
        skippedActionIds.push('1768509581816-vlqt6skyq'); // Botão Dia Específico

        // --- ⏰ TRATAMENTO DE HORÁRIO ---
        console.log('      ⏰ Configurando horário...');
        await wait(1000); // Esperar campos de hora aparecerem

        const timeStr = formatTimeForYouTube(currentRowData.dataPostagem); // Retorna "HH:MM"
        const [hour, minute] = timeStr.split(':');
        console.log(`      🎯 Horário Alvo: ${hour}:${minute}`);

        // Preencher Hora
        const hourInput = document.querySelector('input[data-testid="hour-picker"]');
        if (hourInput) {
          hourInput.focus();
          document.execCommand('selectAll');
          document.execCommand('insertText', false, hour);
          hourInput.dispatchEvent(new Event('change', { bubbles: true }));
          console.log('      ✅ Hora preenchida');
        } else {
          console.warn('      ⚠️ Campo de hora não encontrado');
        }

        await wait(200);

        // Preencher Minuto
        const minuteInput = document.querySelector('input[data-testid="minute-picker"]');
        if (minuteInput) {
          minuteInput.focus();
          document.execCommand('selectAll');
          document.execCommand('insertText', false, minute);
          minuteInput.dispatchEvent(new Event('change', { bubbles: true }));
          console.log('      ✅ Minuto preenchido');
        } else {
          console.warn('      ⚠️ Campo de minuto não encontrado');
        }

      } else if (action.id === '1768509584974-jbgc7zksn') {
        // --- 🛡️ TRATAMENTO ROBUSTO DO BOTÃO "PROGRAMAR" ---
        // O site valida o áudio após upload. Para áudios longos, essa validação
        // pode demorar. O botão fica desabilitado (disabled) até concluir.
        // Aguardamos o botão ficar habilitado antes de clicar.
        console.log('      🛡️ Aguardando botão "Programar" ficar habilitado...');

        const PROGRAMAR_POLL_INTERVAL = 2000; // Verificar a cada 2 segundos
        const PROGRAMAR_MAX_TIMEOUT = 120000; // Timeout máximo: 2 minutos
        const programarBtnSelector = 'button[type="submit"][form="review-form"][data-encore-id="buttonPrimary"]';

        let programarElapsed = 0;
        let programarBtn = null;

        while (programarElapsed < PROGRAMAR_MAX_TIMEOUT) {
          programarBtn = document.querySelector(programarBtnSelector);

          if (programarBtn && !programarBtn.disabled && !programarBtn.getAttribute('aria-disabled')) {
            // Botão encontrado e habilitado!
            console.log(`      ✅ Botão "Programar" habilitado após ${(programarElapsed / 1000).toFixed(0)}s`);
            break;
          }

          // Exibir status no log para acompanhamento
          const disabledStatus = programarBtn
            ? `disabled=${programarBtn.disabled}, aria-disabled=${programarBtn.getAttribute('aria-disabled')}`
            : 'botão não encontrado no DOM';
          console.log(`      ⏳ Botão ainda desabilitado (${(programarElapsed / 1000).toFixed(0)}s/${PROGRAMAR_MAX_TIMEOUT / 1000}s) [${disabledStatus}]`);

          await wait(PROGRAMAR_POLL_INTERVAL);
          programarElapsed += PROGRAMAR_POLL_INTERVAL;
        }

        // Verificação final
        programarBtn = document.querySelector(programarBtnSelector);
        if (!programarBtn || programarBtn.disabled || programarBtn.getAttribute('aria-disabled') === 'true') {
          throw new Error(`Botão "Programar" ainda desabilitado após ${PROGRAMAR_MAX_TIMEOUT / 1000}s. O áudio pode ser muito grande ou ocorreu um erro de validação no Spotify.`);
        }

        // Clicar no botão (no botão pai, não no span)
        console.log('      🚀 Clicando no botão "Programar"...');
        programarBtn.click();

      } else if (action.id === '1768509588599-zmo7n8mai') {
        // --- 🔘 TRATAMENTO DE CLIQUE DURO (BOTÃO FECHAR/PRONTO) ---
        console.log('      🔘 Clicando no botão Fechar (Forçado)...');
        element.click();
        await wait(100);
        element.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true, view: window }));
        await wait(100);
        // Tentar via JS puro também se for um form submit button disfarçado
        if (element.form) element.form.submit();
      } else {
        element.click();
      }
      break;

    case 'input':
      element.focus();

      // ⭐ SUBSTITUIR VALORES DA PLANILHA
      let value = action.value || '';
      let isFileUpload = false;

      if (currentRowData) {
        // Upload de arquivo (input type="file")
        if (action.inputType === 'file' && action.attributes?.name === 'Filedata') {
          const filePath = buildFilePath(currentRowData.nomeArquivo);
          console.log(`         📁 Iniciando upload via debugger: ${filePath}`);

          // Enviar comando para background (chrome.debugger)
          // Selector deve ser CSS válido
          const selector = action.selector.css || `input[name="${action.attributes.name}"]`;

          await new Promise((resolve, reject) => {
            chrome.runtime.sendMessage({
              action: 'uploadFile',
              selector: selector,
              filePath: filePath
            }, (response) => {
              if (chrome.runtime.lastError) {
                reject(chrome.runtime.lastError);
              } else if (response && response.success) {
                console.log('         ✅ Arquivo definido via debugger');
                resolve();
              } else {
                reject(new Error(response?.error || 'Erro desconhecido no upload'));
              }
            });
          });

          isFileUpload = true;
        }
        // Título do vídeo (ID específico da action)
        else if (action.id === '1768509546705-rhsn3quu7') {
          value = currentRowData.tituloVideo;
          console.log(`         📝 Título: ${value}`);
        }
        // Descrição do vídeo (ID específico da action)
        else if (action.id === '1768509562558-56ax0pifv') {
          value = currentRowData.descricaoVideo;
          console.log(`         📄 Descrição (Rich Text): ${value.substring(0, 50)}...`);

          // --- 📝 TRATAMENTO VIA CLIPBOARD PASTE (Slate-Safe) ---
          // execCommand('insertText') e manipulação de seleção estão causando crash no React.
          // Eventos de 'paste' são sanitizados pelo Slate e geralmente seguros.
          try {
            element.focus();
            await wait(300);

            // Simular evento de colar (Clipboard API)
            // Isso evita mexer na seleção ou usar comandos proibidos
            const dataTransfer = new DataTransfer();
            dataTransfer.setData('text/plain', value);

            const pasteEvent = new ClipboardEvent('paste', {
              bubbles: true,
              cancelable: true,
              clipboardData: dataTransfer
            });

            // Disparar no elemento editável
            element.dispatchEvent(pasteEvent);
            await wait(100);

            // Enviar input event apenas para garantir que validadores de formulário (não Slate) percebam
            // Mas com inputType 'insertFromPaste' para consistência
            const inputEvent = new InputEvent('input', {
              bubbles: true,
              inputType: 'insertFromPaste',
              data: value
            });
            element.dispatchEvent(inputEvent);

            console.log('         ✅ Texto inserido via Simulação de Paste (Crash Safe)');

          } catch (e) {
            console.error('         ❌ Erro na simulação de paste:', e);
            // Fallback: value direto (pode não validar, mas não deve crashar)
            element.textContent = value;
            element.dispatchEvent(new Event('input', { bubbles: true }));
          }

          isFileUpload = true;
        }



        // Data de postagem (Complexo: Click Trigger -> Input in Popup)
        else if (action.id === '1768509576488-bqmrfufae') {
          const dateValue = formatDateForYouTube(currentRowData.dataPostagem);
          console.log(`         📅 Data (Via Popup): ${dateValue}`);

          // 1. Clicar no trigger para abrir o calendário
          if (element) {
            element.click();
            await wait(500); // Esperar popup abrir

            // 2. Procurar o input dentro do popup (geralmente criado no final do body)
            // Tenta seletores comuns do datepicker do YT
            const dateInput = document.querySelector('ytcp-date-picker input') ||
              document.querySelector('tp-yt-paper-input[label*="Data"] input') ||
              document.querySelector('input[aria-label*="Data"]');

            if (dateInput) {
              dateInput.value = dateValue;
              dateInput.dispatchEvent(new Event('input', { bubbles: true }));
              dateInput.dispatchEvent(new Event('change', { bubbles: true }));

              // Tentar simular Enter para fechar/confirmar
              dateInput.dispatchEvent(new KeyboardEvent('keydown', {
                key: 'Enter',
                code: 'Enter',
                which: 13,
                keyCode: 13,
                bubbles: true
              }));
              console.log('         ✅ Data definida no popup');
            } else {
              console.warn('         ⚠️ Input de data não encontrado no popup');
            }
          }
          isFileUpload = true; // Impede o script de tentar escrever no trigger (que é uma div)
        }
        // Horário de postagem (Dinâmico da planilha)
        else if (action.id === '1768508690124-013p4kja4') {
          value = formatTimeForYouTube(currentRowData.dataPostagem);
          console.log(`         ⏰ Horário: ${value}`);
        }

      }

      if (!isFileUpload) {
        if (element.isContentEditable) {
          element.textContent = value;
        } else {
          element.value = value;
        }
        element.dispatchEvent(new Event('input', { bubbles: true }));
        element.dispatchEvent(new Event('change', { bubbles: true }));
      }
      break;

    case 'select':
      element.value = action.value || '';
      element.dispatchEvent(new Event('change', { bubbles: true }));
      break;

    case 'checkbox':
    case 'radio':
      if (element.checked !== action.checked) {
        element.click();
      }
      break;

    case 'submit':
      element.submit();
      break;

    case 'navigate':
      if (action.url && action.url !== window.location.href) {
        // Soft Navigation Check:
        // If we are navigating to a wizard/setup page, and we are ALREADY on a generic wizard/setup page,
        // we might not want to force a reload if the IDs differ (because the site might have generated a new ID).

        // Soft Navigation Check:
        // If we are navigating to a wizard/setup page, and we are ALREADY on a generic wizard/setup page,
        // we might not want to force a reload if the IDs differ (because the site might have generated a new ID).

        const currentUrl = window.location.href;
        const targetUrl = action.url;
        const isTargetWizard = targetUrl.includes('/episode/') && targetUrl.includes('/wizard');
        const isCurrentWizard = currentUrl.includes('/episode/') && currentUrl.includes('/wizard');

        if (currentUrl === targetUrl) {
          console.log(`   ⚠️ Soft Navigation: Já estamos na URL exata. Pulando navegação.`);
        } else if (isTargetWizard && isCurrentWizard) {
          console.log(`   ⚠️ Soft Navigation: Já estamos em uma página Wizard. Pulando navegação forçada para ${targetUrl}`);
          // We assume the current page is the correct "new" draft location
        } else {
          console.log(`   🧭 Navegando para: ${action.url}`);

          // Safety delay to ensure storage saves
          await wait(500);

          // Force stop loop explicitly
          isReplaying = false;

          window.location.assign(action.url);

          // Throwing error to ensure we KILL the current execution context immediately
          // and don't accidentally continue the loop while the browser thinks about reloading.
          throw new Error("RELOADING_PAGE");
        }
      }
      break;

    default:
      console.warn('Unknown action type:', action.type);
  }
}

// Find element using selector strategies with efficient polling
function findElement(selectorObj, timeout = 30000) {
  return new Promise((resolve) => {
    let startTime = Date.now();

    const check = () => {
      // Try CSS selector
      if (selectorObj.css) {
        try {
          const element = document.querySelector(selectorObj.css);
          if (element) return element;
        } catch (e) {
          console.warn('CSS selector failed:', e);
        }
      }

      // Try XPath selector
      if (selectorObj.xpath) {
        try {
          const result = document.evaluate(
            selectorObj.xpath,
            document,
            null,
            XPathResult.FIRST_ORDERED_NODE_TYPE,
            null
          );
          if (result.singleNodeValue) return result.singleNodeValue;
        } catch (e) {
          console.warn('XPath selector failed:', e);
        }
      }
      return null;
    };

    // Check immediately
    const immediate = check();
    if (immediate) {
      resolve(immediate);
      return;
    }

    // Poll
    const interval = setInterval(() => {
      const element = check();
      if (element) {
        clearInterval(interval);
        resolve(element);
      } else if (Date.now() - startTime > timeout) {
        clearInterval(interval);
        resolve(null);
      }
    }, 200); // Poll every 200ms
  });
}

// Wait for a loader/spinner to disappear
function waitForLoaderToDisappear(selector, timeout = 10000) {
  return new Promise((resolve) => {
    console.log(`⏳ Aguardando desaparecimento de: ${selector}`);

    // If it doesn't exist initially, we are done
    if (!document.querySelector(selector)) {
      resolve();
      return;
    }

    const startTime = Date.now();
    const interval = setInterval(() => {
      if (!document.querySelector(selector)) {
        clearInterval(interval);
        console.log("   ✅ Loader desapareceu.");
        resolve();
      } else if (Date.now() - startTime > timeout) {
        clearInterval(interval);
        console.warn("   ⚠️ Timeout: Loader não desapareceu, mas seguindo...");
        resolve();
      }
    }, 300);
  });
}

// Highlight element during replay
function highlightElement(element) {
  const original = {
    outline: element.style.outline,
    outlineOffset: element.style.outlineOffset
  };

  element.style.outline = '3px solid #38ef7d';
  element.style.outlineOffset = '2px';

  setTimeout(() => {
    element.style.outline = original.outline;
    element.style.outlineOffset = original.outlineOffset;
  }, 800);
}

// Wait utility
function wait(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// ========== HELPER FUNCTIONS ==========

/**
 * Constrói o caminho completo do arquivo
 * Usa a pasta configurada + nome do arquivo
 */
function buildFilePath(fileName) {
  if (!config || !config.videosFolder) {
    return fileName; // Retorna apenas o nome se não tiver pasta configurada
  }

  // Remover barras extras
  let folder = config.videosFolder.replace(/[\\/]$/, '');

  // Detectar SO (simplificado)
  const isWindows = folder.includes(':') || folder.includes('\\');
  const separator = isWindows ? '\\' : '/';

  return `${folder}${separator}${fileName}`;
}

/**
 * Formata data da planilha (DD/MM/YYYY HH:MM) para formato do YouTube (DD/MM/YYYY)
 */
function formatDateForYouTube(dateTimeStr) {
  if (!dateTimeStr) return '';

  // Esperado: "16/01/2026 20:00" -> "16 de jan. de 2026" (dependendo do locale)
  // Mas como o input do YouTube aceita DD/MM/YYYY direto se for text input:

  const parts = dateTimeStr.split(' ');
  return parts[0]; // Retorna "16/01/2026"
}

/**
 * Extrai horário da data da planilha
 */
function formatTimeForYouTube(dateTimeStr) {
  if (!dateTimeStr) return '20:00'; // Default

  const parts = dateTimeStr.split(' ');
  if (parts.length > 1) {
    return parts[1]; // Retorna "20:00"
  }
  return '20:00';
}

/**
 * Formata data para Spotify (Extenso PT-BR)
 * Ex: "13/02/2026" -> "13 de fevereiro de 2026"
 */
function formatDateForSpotify(dateTimeStr) {
  if (!dateTimeStr) return '';
  // Formato esperado: "DD/MM/YYYY HH:MM"
  const datePart = dateTimeStr.split(' ')[0];
  const [day, month, year] = datePart.split('/');

  if (!day || !month || !year) return dateTimeStr;

  const months = [
    "janeiro", "fevereiro", "março", "abril", "maio", "junho",
    "julho", "agosto", "setembro", "outubro", "novembro", "dezembro"
  ];

  const monthIndex = parseInt(month, 10) - 1;
  const monthName = months[monthIndex] || month; // Fallback

  return `${parseInt(day, 10)} de ${monthName} de ${year}`;
}

/**
 * Notifica erro ao popup
 */
function notifyError(message) {
  chrome.runtime.sendMessage({
    action: 'replayComplete',
    success: false,
    message: message
  }).catch(() => { });
}

// ========== PERSISTENCE HELPERS ==========

async function saveReplayState(mode) {
  const state = {
    isReplaying: true,
    mode: mode,
    currentActionIndex: currentActionIndex,
    currentRowIndex: currentRowIndex, // Important for loop
    timestamp: Date.now(),
    // We only save basic config and rows if in loop mode, 
    // but saving them always is safer if small enough.
    config: config,
    pendingRows: pendingRows
  };

  return new Promise((resolve) => {
    try {
      chrome.storage.local.set({ 'spotifyReplayState': state }, () => {
        if (chrome.runtime.lastError) {
          console.error("❌ Erro fatal ao salvar estado:", chrome.runtime.lastError);
        } else {
          // console.log("💾 Estado salvo (Sync)");
        }
        resolve();
      });
    } catch (e) {
      console.error("❌ Exceção ao salvar estado:", e);
      resolve();
    }
  });
}

async function restoreReplayState() {
  return new Promise((resolve) => {
    chrome.storage.local.get(['spotifyReplayState'], (result) => {
      resolve(result.spotifyReplayState || null);
    });
  });
}

async function clearReplayState() {
  return new Promise((resolve) => {
    chrome.storage.local.remove(['spotifyReplayState'], () => {
      resolve();
    });
  });
}
